  ('police-8b7f1efc-moex-00579', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '道路交通管理處罰條例規定，機車駕駛人未依規定戴安全帽者，處新臺幣500元罰鍰。有關 此規定，下列敘述何者正確？', '["不戴安全帽並非憲法所保障之基本權利", "處新臺幣500元罰鍰顯屬輕微，尚未對人民之基本權利構成限制", "條例非法律，此規定違反法律保留原則", "此規定之目的係為增進公共利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00580', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '關於總統、副總統之缺位與繼任，下列敘述何者錯誤？', '["副總統缺位時，總統應於3個月內提名候選人，由立法院補選，繼任至原任期屆滿為止", "我國曾出現總統缺位、副總統繼任，但無副總統補選之憲政經驗", "總統缺位時，由副總統繼任，至總統任期屆滿為止", "行政院院長代行總統職權時，其期限不得逾2個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00581', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依現行規定，下列何者非立法院之職權？', '["法律案之議決權", "條約案之議決權", "國家重要事項之參與決策權", "行政院院長任命之同意權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
