  ('police-8b7f1efc-moex-00583', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官審理案件法規定，關於憲法法庭審理政黨違憲解散案件之程序，下列敘述何 者正確？', '["憲法法庭行言詞辯論，須有大法官現有總額三分之二以上出席", "以書面審理為原則，必要時，得行言詞辯論", "得囑託檢察官或調度司法警察為搜索、扣押", "作成附具理由書之解釋，大法官得提出不同意見書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00584', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官解釋，關於立法委員之質詢及政府人員之備詢，下列敘述何者錯誤？', '["立法院對政府人員的質詢權，源自於行政院應對立法院負責的憲法規定", "立法院邀請政府人員出席備詢時，行政院各部會首長及其所屬人員，除依法獨立行使職權， 不受外部干涉之人員外，均有應邀說明之義務", "質詢權係為貫徹民意政治及責任政治之制度設計", "地方自治團體辦理自治事項仍受中央政府之適法監督，故受立法院邀請出席備詢時，亦有 應邀說明之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
