  ('police-8b7f1efc-moex-00586', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依憲法、增修條文及司法院大法官解釋，關於罷免，下列敘述何者錯誤？', '["總統、副總統之罷免，須經立法委員之提案，選舉人總額過半數之投票，且有效票過半數 同意罷免時，方能通過", "總統、副總統之彈劾案如不成立，立法院即不得再提案罷免", "對於操守不佳之大法官，仍不能透過罷免追究其責任", "直轄市、縣市立法委員之罷免，僅原選舉區之選舉人方有投票權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
